#[derive(Debug, Default, Clone)]
pub struct HandState {
    pub unique_id: Option<String>,
    pub priority: i32,
    pub chirality: Chirality,
    pub is_device_active: bool,
    pub is_tracking: bool,
    pub tracks_metacarpals: bool,
    pub confidence: f32,
    pub wrist_position: Vector3<f32>,
    pub wrist_rotation: Quaternion<f32>,
    pub segment_positions: Vec<Vector3<f32>>,
    pub segment_rotations: Vec<Quaternion<f32>>,
}

impl MemoryPackable for HandState {
    fn pack(&mut self, packer: &mut MemoryPacker<'_>) {
        packer.write_str(self.unique_id.as_ref().map(|s| s.as_str()));
        packer.write(&self.priority);
        packer.write_object_required(&mut self.chirality);
        packer.write_packed_bools(self.is_device_active, self.is_tracking, self.tracks_metacarpals, false, false, false, false, false);
        packer.write(&self.confidence);
        if self.is_tracking {
            packer.write(&self.wrist_position);
            packer.write(&self.wrist_rotation);
            packer.write_value_list(Some(&self.segment_positions));
            packer.write_value_list(Some(&self.segment_rotations));
        }
    }
    fn unpack<P: MemoryPackerEntityPool>(&mut self, unpacker: &mut MemoryUnpacker<'_, '_, P>) {
        self.unique_id = unpacker.read_str();
        self.priority = unpacker.read();
        unpacker.read_object_required(&mut self.chirality);
        let __p = unpacker.read_packed_bools();
        self.is_device_active = __p.bit0;
        self.is_tracking = __p.bit1;
        self.tracks_metacarpals = __p.bit2;
        self.confidence = unpacker.read();
        if self.is_tracking {
            self.wrist_position = unpacker.read();
            self.wrist_rotation = unpacker.read();
            self.segment_positions = unpacker.read_value_list();
            self.segment_rotations = unpacker.read_value_list();
        }
    }
}

