#[derive(Clone, Copy, Debug, Default, PartialEq)]
#[repr(i32)]
pub enum RectOrientation {
    #[default]
    default = 0,
    clockwise90 = 1,
    upside_down180 = 2,
    counter_clockwise90 = 3,
}

impl MemoryPackable for RectOrientation {
    fn pack(&mut self, packer: &mut MemoryPacker<'_>) {
        packer.write(&(*self as i32));
    }
    fn unpack<P: MemoryPackerEntityPool>(&mut self, unpacker: &mut MemoryUnpacker<'_, '_, P>) {
        unsafe { std::ptr::write(self as *mut Self, std::mem::transmute::<i32, Self>(unpacker.read::<i32>())) };
    }
}

impl EnumRepr for RectOrientation {
    fn as_i32(self) -> i32 {
        self as i32
    }
    fn from_i32(i: i32) -> Self {
        unsafe { std::mem::transmute::<i32, Self>(i) }
    }
}

unsafe impl Pod for RectOrientation {}
unsafe impl Zeroable for RectOrientation {}

